import pytest
from source import find_in_sorted

def test_find_last_element_upper_half_no_infinite_recursion():
    try:
        result = find_in_sorted([3, 4, 5, 6, 7], 7)
    except RecursionError:
        pytest.fail("find_in_sorted([3, 4, 5, 6, 7], 7) caused infinite recursion — mid should be mid+1 when recursing into upper half")
    assert result == 4, f"Expected index 4 for value 7 in [3, 4, 5, 6, 7], got {result}"
